9: message EvaluationRequest {
10:   string request_id = 1;
11:   string namespace_key = 2;
12:   string flag_key = 3;
13:   string entity_id = 4;
14:   map<string, string> context = 5;
15:   string reference = 6;
16: }
17: 
18: message BatchEvaluationRequest {
19:   string request_id = 1;
20:   repeated EvaluationRequest requests = 3;
21:   string reference = 4;
22: }
23: 
24: message BatchEvaluationResponse {
25:   string request_id = 1;
26:   repeated EvaluationResponse responses = 2;
27:   double request_duration_millis = 3;
28: }
29: 
30: enum EvaluationReason {
31:     UNKNOWN_EVALUATION_REASON = 0;
32:     FLAG_DISABLED_EVALUATION_REASON = 1;
33:     MATCH_EVALUATION_REASON = 2;
34:     DEFAULT_EVALUATION_REASON = 3;
35: }
36: 
37: enum ErrorEvaluationReason {
38:   UNKNOWN_ERROR_EVALUATION_REASON = 0;
39:   NOT_FOUND_ERROR_EVALUATION_REASON = 1;
40: }
41: 
42: enum EvaluationResponseType {
43:   VARIANT_EVALUATION_RESPONSE_TYPE = 0;
44:   BOOLEAN_EVALUATION_RESPONSE_TYPE = 1;
45:   ERROR_EVALUATION_RESPONSE_TYPE = 2;
46: }
47: 
48: message EvaluationResponse {
49:     EvaluationResponseType type = 1;
50:     oneof response {
51:         BooleanEvaluationResponse boolean_response = 2;
52:         VariantEvaluationResponse variant_response = 3;
53:         ErrorEvaluationResponse error_response = 4;
54:     }
55: }
56: 
57: message BooleanEvaluationResponse {
58:   bool enabled = 1;
59:   EvaluationReason reason = 2;
60:   string request_id = 3;
61:   double request_duration_millis = 4;
62:   google.protobuf.Timestamp timestamp = 5;
63:   string flag_key = 6;
64: }
65: 
66: message VariantEvaluationResponse {
67:   bool match = 1;
68:   repeated string segment_keys = 2;
69:   EvaluationReason reason = 3;
70:   string variant_key = 4;
71:   string variant_attachment = 5;
72:   string request_id = 6;
73:   double request_duration_millis = 7;
74:   google.protobuf.Timestamp timestamp = 8;
75:   string flag_key = 9;
76: }
77: 
78: message ErrorEvaluationResponse {
79:   string flag_key = 1;
80:   string namespace_key = 2;
81:   ErrorEvaluationReason reason = 3;
82: }
83: 
84: service EvaluationService {
85:   rpc Boolean(EvaluationRequest) returns (BooleanEvaluationResponse) {}
86:   rpc Variant(EvaluationRequest) returns (VariantEvaluationResponse) {}
87:   rpc Batch(BatchEvaluationRequest) returns (BatchEvaluationResponse) {}
88: }
89: 
90: message EvaluationDistribution {
91:   string id = 1;
92:   string rule_id = 2;
93:   string variant_id = 3;
94:   string variant_key = 4;
95:   string variant_attachment = 5;
96:   float rollout = 6;
97: }
98: 
99: enum EvaluationRolloutType {
100:   UNKNOWN_ROLLOUT_TYPE = 0;
101:   SEGMENT_ROLLOUT_TYPE = 1;
102:   THRESHOLD_ROLLOUT_TYPE = 2;
103: }
104: 
105: message EvaluationRollout {
106:   EvaluationRolloutType type = 1;
107:   int32 rank = 2;
108:   oneof rule {
109:     EvaluationRolloutSegment segment = 3;
110:     EvaluationRolloutThreshold threshold = 4;
111:   }
112: }
113: 
114: message EvaluationRolloutThreshold {
115:   float percentage = 1;
116:   bool value = 2;
117: }
118: 
119: enum EvaluationSegmentOperator {
120:   OR_SEGMENT_OPERATOR = 0;
121:   AND_SEGMENT_OPERATOR = 1;
122: }
123: 
124: message EvaluationRolloutSegment {
125:   bool value = 1;
126:   EvaluationSegmentOperator segment_operator = 2;
127:   repeated EvaluationSegment segments = 3;
128: }
129: 
130: enum EvaluationSegmentMatchType {
131:   ALL_SEGMENT_MATCH_TYPE = 0;
132:   ANY_SEGMENT_MATCH_TYPE = 1;
133: }
134: 
135: message EvaluationSegment {
136:   string key = 1;
137:   string name = 2;
138:   string description = 3;
139:   EvaluationSegmentMatchType match_type = 4;
140:   google.protobuf.Timestamp created_at = 5;
141:   google.protobuf.Timestamp updated_at = 6;
142:   repeated EvaluationConstraint constraints = 7;
143: }
144: 
145: enum EvaluationFlagType {
146:   VARIANT_FLAG_TYPE = 0;
147:   BOOLEAN_FLAG_TYPE = 1;
148: }
149: 
150: message EvaluationFlag {
151:   string key = 1;
152:   string name = 2;
153:   string description = 3;
154:   bool enabled = 4;
155:   EvaluationFlagType type = 5;
156:   google.protobuf.Timestamp created_at = 6;
157:   google.protobuf.Timestamp updated_at = 7;
158:   repeated EvaluationRule rules = 8;
159:   repeated EvaluationRollout rollouts = 9;
160: }
161: 
162: enum EvaluationConstraintComparisonType {
163:   UNKNOWN_CONSTRAINT_COMPARISON_TYPE = 0;
164:   STRING_CONSTRAINT_COMPARISON_TYPE = 1;
165:   NUMBER_CONSTRAINT_COMPARISON_TYPE = 2;
166:   BOOLEAN_CONSTRAINT_COMPARISON_TYPE = 3;
167:   DATETIME_CONSTRAINT_COMPARISON_TYPE = 4;
168:   ENTITY_ID_CONSTRAINT_COMPARISON_TYPE = 5;
169: }
170: 
171: message EvaluationConstraint {
172:   string id = 1;
173:   EvaluationConstraintComparisonType type = 2;
174:   string property = 3;
175:   string operator = 4;
176:   string value = 5;
177: }
178: 
179: message EvaluationRule {
180:   string id = 1;
181:   repeated EvaluationSegment segments = 2;
182:   int32 rank = 3;
183:   EvaluationSegmentOperator segment_operator = 4;
184:   repeated EvaluationDistribution distributions = 5;
185: }
186: 
187: message EvaluationNamespace {
188:   string key = 1;
189: }
190: 
191: message EvaluationNamespaceSnapshot {
192:   EvaluationNamespace namespace = 1;
193:   repeated EvaluationFlag flags = 2;
194: }
195: 
196: message EvaluationNamespaceSnapshotRequest {
197:   string key = 1;
198:   string reference = 2;
199: }
200: 
